#!/usr/bin/env bash
# poc-poc.sh — POC / 原型验证（「想法 → POC」） SOP walkthrough for AI 产品经理 (LLM 应用 / 生成式 AI / Agent 产品 / Copilot 嵌入 — 跨模型评估 / 工作流设计 / 产品-工程协同).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AI 产品经理 (LLM 应用 / 生成式 AI / Agent 产品 / Copilot 嵌入 — 跨模型评估 / 工作流设计 / 产品-工程协同)"
WORKFLOW="POC / 原型验证（「想法 → POC」）"

usage() {
  cat <<EOF
poc-poc.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./poc-poc.sh             # interactive
  ./poc-poc.sh --dry-run
  ./poc-poc.sh --json
  ./poc-poc.sh --explain
  ./poc-poc.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "POC / 原型验证（「想法 → POC」）" 工作流。

一句话: 用一个「为学习而造、随时可抛弃」的原型，在投入真正工程资源前回答「技术上行不行 + 体验上用户要不要」—— 从「scoping 假设」状态到「go / pivot / kill 有依据」状态。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • Eval 是地基,不是可选项（别 vibe-check）: 「AI 产品的『好』不是看几个 case 觉得行就 ship —— 是先针对你**自己产品的失败模式**建一套可重复、可回归的系统化测量;没有 eval 就是在瞎改。」
  • 先 error analysis,再加功能（PM 亲自看 trace）: 「质量上不去时,资深 AI PM 的第一反应**不是加功能**,是 PM 亲自拉 10-50 个真实 trace（trace 条数量级见 Hamel field-guide T03-S001 / ev

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**明确这个 POC 要回答的问题**：是「技术可行性」还是「用户 desirability」还是「成本」？一个 POC 别想回答全部。PM 主导。跳过 → 造了个什么都证明不了的 demo。 (evidence: [T03-S010])"
  "**造「为学习」的原型，不是「为交付」**：明确这是 throwaway code，工程师不用写测试、不用考虑扩展性。PM + 工程师达成共识。跳过 → 把原型代码当 MVP 地基，背上技术债且不敢推翻。 (evidence: [T03-S010])"
  "**用真实约束喂原型**：合成数据要 ground 在真实业务规则 / 真实数据样本上，不能凭空编。PM + 领域专家。跳过 → demo 在假数据上很美，碰真数据就崩（06-glossary「demo-to-production gap」）。 (evidence: [T03-S001])"
  "**拿原型做真实用户/领域专家测试**：观察真人用，尤其看 desirability。PM 主导。跳过 → 技术跑通了，但没人要——AI 唯一不能自动解决的就是 desirability。 (evidence: [T03-S011])"
  "**下 go / pivot / kill 结论并记录学到什么**：PM 主导。跳过 → POC 变成「一直在 POC」，沉没成本拖着不决策。"
)
declare -a FAILURE_MODES=(
  "**原型「悄悄转正」**：触发原因 = throwaway code 写得还行，舍不得删；怎么避免 = step 2 一开始就和工程师白纸黑字约定这是 throwaway。（**CLI 自检项**：Is your team treating the POC code as the MVP foundation? If yes — you skipped \"build to learn\"; the code should be deleted, not extended.） (evidence: [T03-S010])"
  "**在假数据上做出漂亮 demo**：触发原因 = 真数据难拿，编一个快；怎么避免 = 合成数据强制 ground 在真实 listing / schedule / 业务规则上。（**CLI 自检项**：Is your demo running on invented data? Re-run it on real (or real-constrained synthetic) data before drawing any conclusion.） (evidence: [T03-S001])"
  "**只验技术、不验 desirability**：触发原因 = 技术可行性好量化、用户要不要难量化；怎么避免 = step 4 强制至少看 3-5 个真人用原型。（**CLI 自检项**：Did a real user actually try this prototype, or only your team? \"Can we build it\" ≠ \"should it exist\".） (evidence: [T03-S011])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "poc-poc-walkthrough"
fi
